INSERT INTO public.businesses (owner_id, business_name, name, category, address, city, state, zip_code, phone, website, description, banner_url, listing_status, is_verified)
SELECT 'bd72a75e-1310-4f40-9c74-380443b09d9b'::uuid, n.business_name, n.business_name, n.category, n.address, n.city, n.state, n.zip_code, n.phone, n.website, n.description, n.banner_url, 'live', true
FROM new_hotels n
WHERE NOT EXISTS (
  SELECT 1 FROM public.businesses b
  WHERE lower(regexp_replace(b.business_name,'[^A-Za-z0-9]+','','g')) = lower(regexp_replace(n.business_name,'[^A-Za-z0-9]+','','g'))
);